import{_ as e,j as s,o as a,v as n}from"./chunks/framework.OlxNbC8G.js";const t="/assets/message-queue-small-3.psV3COIL.webp",u=JSON.parse('{"title":"Message queue là gì ?","description":"","frontmatter":{"footer":true,"title":"Message queue là gì ?","authors":["lethanh"],"date":"2024-04-15T00:00:00.000Z","outline":"deep","draft":true,"group":"2. Message and event stream"},"headers":[{"level":2,"title":"Vậy Message queue là gì ?","slug":"vay-message-queue-la-gi","link":"#vay-message-queue-la-gi","children":[]},{"level":2,"title":"Các thành phần chính của Message queue.","slug":"cac-thanh-phan-chinh-cua-message-queue","link":"#cac-thanh-phan-chinh-cua-message-queue","children":[]},{"level":2,"title":"Producers và consumers","slug":"producers-va-consumers","link":"#producers-va-consumers","children":[{"level":3,"title":"Message producers","slug":"message-producers","link":"#message-producers","children":[{"level":4,"title":"Ví dụ Message producers","slug":"vi-du-message-producers","link":"#vi-du-message-producers","children":[]}]},{"level":3,"title":"Consumer producers","slug":"consumer-producers","link":"#consumer-producers","children":[]}]},{"level":2,"title":"Mô tả đơn giản các thức hoạt động của Message Queue.","slug":"mo-ta-đon-gian-cac-thuc-hoat-đong-cua-message-queue","link":"#mo-ta-đon-gian-cac-thuc-hoat-đong-cua-message-queue","children":[]},{"level":2,"title":"Ưu điểm của Message Queue","slug":"uu-điem-cua-message-queue","link":"#uu-điem-cua-message-queue","children":[]},{"level":2,"title":"REF:","slug":"ref","link":"#ref","children":[]}],"relativePath":"study/thanhlv-study-2024/2024-04-15-message-queue-la-gi.md","filePath":"study/thanhlv-study-2024/2024-04-15-message-queue-la-gi.md","lastUpdated":1715608820000}'),r={name:"study/thanhlv-study-2024/2024-04-15-message-queue-la-gi.md"},g=[n('<h1 id="message-queue-la-gi" tabindex="-1">Message queue là gì ? <a class="header-anchor" href="#message-queue-la-gi" aria-label="Permalink to &quot;Message queue là gì ?&quot;">​</a></h1><p>Kiến thức đầu tiên chúng ta đã cùng học với nhau là <a href="./2024-04-15-message-la-gi.html"><strong>Message</strong></a>, trong bài viết này chúng ta sẽ cùng nhau tìm hiểu về <a href="./2024-04-15-message-queue-la-gi.html"><strong>Message queue</strong></a>, một khái niệm quan trọng mà các hệ thống lớn thường sử dụng để gửi và nhận các tin nhắn giữa các thành phần của chúng.</p><nav class="table-of-contents"><ul><li><a href="#vay-message-queue-la-gi">Vậy Message queue là gì ?</a></li><li><a href="#cac-thanh-phan-chinh-cua-message-queue">Các thành phần chính của Message queue.</a></li><li><a href="#producers-va-consumers">Producers và consumers</a><ul><li><a href="#message-producers">Message producers</a><ul><li><a href="#vi-du-message-producers">Ví dụ Message producers</a></li></ul></li><li><a href="#consumer-producers">Consumer producers</a></li></ul></li><li><a href="#mo-ta-đon-gian-cac-thuc-hoat-đong-cua-message-queue">Mô tả đơn giản các thức hoạt động của Message Queue.</a></li><li><a href="#uu-điem-cua-message-queue">Ưu điểm của Message Queue</a></li><li><a href="#ref">REF:</a></li></ul></nav><h2 id="vay-message-queue-la-gi" tabindex="-1">Vậy Message queue là gì ? <a class="header-anchor" href="#vay-message-queue-la-gi" aria-label="Permalink to &quot;Vậy Message queue là gì ?&quot;">​</a></h2><p><img src="/assets/message-queue-small.8v9U7Oat.webp" alt="message-queue-small"></p><p><a href="./2024-04-15-message-queue-la-gi.html"><strong>Message queue (Hàng đợi tin nhấn)</strong></a> là một component trong <a href="./../../blog/2024-02-01-tim-hieu-ve-architecture.html">system&#39;s architecture</a> hỗ trợ buffer và phân phối các request bất đồng bộ.<br><img src="/assets/Producer-Consumer-buffer.JWr6d-78.png" alt="Producer-Consumer-buffer"></p><p>Cơ chế của <a href="./2024-04-15-message-queue-la-gi.html"><strong>Message queue (Hàng đợi tin nhấn)</strong></a> là lưu trữ các tin nhắn (<a href="./2024-04-15-message-la-gi.html"><strong>Message</strong></a>) trong một hàng đợi(Queue) theo thứ tự tuần tự hoặc ưu tiên và sẽ được chuyển đến một đích(Thành phần nhận, Consumer ) đã chỉ định.</p><p>Những <a href="./2024-04-15-message-la-gi.html"><strong>Message</strong></a> chưa thể gửi đến Consumer đã chỉ định sẽ tiếp tục ở trong Queue cho đến khi Consumer sẵn sàng để xử lý Message.</p><p>Trong một hệ thống có <a href="./2024-04-15-message-queue-la-gi.html"><strong>Message queue (Hàng đợi tin nhấn)</strong></a>, các tin nhắn được gửi từ một ứng dụng <strong>A</strong> đến ứng dụng <strong>B</strong> sẽ được tạm thời lưu trữ trong hàng đợi(Queue) trước khi được ứng dụng B lấy ra và xử lý. Điều này sẽ cho phép các ứng dụng làm việc độc lập với nhau, không cần kết nối trực tiếp.</p><h2 id="cac-thanh-phan-chinh-cua-message-queue" tabindex="-1">Các thành phần chính của Message queue. <a class="header-anchor" href="#cac-thanh-phan-chinh-cua-message-queue" aria-label="Permalink to &quot;Các thành phần chính của Message queue.&quot;">​</a></h2><p><img src="'+t+'" alt="message-queue-small-3"></p><ul><li><strong>Producer</strong>: Là (bộ phận/thành phần) tạo ra <a href="./2024-04-15-message-la-gi.html"><strong>Message</strong></a> chứa các thông tin để tương tác với thành phần khác. <a href="./2024-04-15-message-la-gi.html"><strong>Message</strong></a> này sẽ được truyền vào <a href="./2024-04-15-message-queue-la-gi.html"><strong>Message queue (Hàng đợi tin nhấn)</strong></a>.</li><li><strong>Consumer</strong>: Là (bộ phận/thành phần) trong hệ thống nhận <a href="./2024-04-15-message-la-gi.html"><strong>Message</strong></a> từ Producer thông qua <a href="./2024-04-15-message-queue-la-gi.html"><strong>Message queue (Hàng đợi tin nhấn)</strong></a> để xử lý tin nhắn.</li><li><a href="./2024-04-15-message-la-gi.html"><strong>Message</strong></a>: Thông tin(Thông điệp) thường được tạo dạng text hoặc JSON, tuy nhiên nó có thể là Binary hoặc bất kỳ dạng nào. <a href="./2024-04-15-message-la-gi.html"><strong>Message</strong></a> sẽ do Producer tạo ra.</li><li><strong>Message Queue</strong>: Nơi lưu trữ tạm thời các <a href="./2024-04-15-message-la-gi.html"><strong>Message</strong></a> cho tới khi Consumer lấy ra và xử lý.</li><li><strong>Broker</strong>: Xử lý Message và quản lý <a href="./2024-04-15-message-la-gi.html"><strong>Message</strong></a> để đảm bảo Producer và Consumer sẽ truyền thông tin được cho nhau, Broker giúp định tuyến Message đến đúng queue, quản lý trạng thái của Queue, và đảm bảo <a href="./2024-04-15-message-la-gi.html"><strong>Message</strong></a> được chuyển đến đúng Consumer và không bị mất message. <ul><li>thành phần EXCHANGES sẽ nằm trong Broker, EXCHANGES sẽ giúp định tuyến Message đến đúng queue.</li></ul></li><li><strong>Channel</strong> : là cơ chế truyền thông tin giữa Producer và Consumer thông qua Message Queue. Channel đóng vai trò như là một cầu nối để truyền Message qua lại giữa các bên. Mỗi channel là một kết nối riêng biệt giữa thành phần đến Broker.</li></ul><h2 id="producers-va-consumers" tabindex="-1">Producers và consumers <a class="header-anchor" href="#producers-va-consumers" aria-label="Permalink to &quot;Producers và consumers&quot;">​</a></h2><p><img src="'+t+'" alt="message-queue-small-3"></p><h3 id="message-producers" tabindex="-1">Message producers <a class="header-anchor" href="#message-producers" aria-label="Permalink to &quot;Message producers&quot;">​</a></h3><p>Producer là một thành phần thực hiện tạo ra <a href="./2024-04-15-message-la-gi.html"><strong>Message</strong></a> và gửi <a href="./2024-04-15-message-la-gi.html"><strong>Message</strong></a> đó đến Queue.</p><p>Các Producer thường đóng vai trò là nguồn cung cấp, tạo <a href="./2024-04-15-message-la-gi.html"><strong>Message</strong></a> hoặc <a href="./2024-04-16-event-la-gi.html"><strong>Event</strong></a> để cung cấp cho các hệ thống ví dụ <a href="./2024-04-15-message-queue-la-gi.html"><strong>Message queue (Hàng đợi tin nhấn)</strong></a> hoặc <a href="./2024-04-21-event-stream-va-event-stream-platform-la-gi.html">Event Stream</a> hoặc các hệ thống khác.</p><h4 id="vi-du-message-producers" tabindex="-1">Ví dụ Message producers <a class="header-anchor" href="#vi-du-message-producers" aria-label="Permalink to &quot;Ví dụ Message producers&quot;">​</a></h4><ul><li>Bạn và bạn bè(<strong>producer</strong>) vào 1 nhà hàng và thực hiện yêu cầu gọi món ăn(<strong>Message request</strong>) và giao nó cho người phục vụ(<strong>Message Queue</strong>), người phục vụ sẽ giữ và giao tất cả các Message Order đến nhà bếp(<strong>Consumer</strong>) nơi thực hiện phục vụ yêu cầu</li></ul><h3 id="consumer-producers" tabindex="-1">Consumer producers <a class="header-anchor" href="#consumer-producers" aria-label="Permalink to &quot;Consumer producers&quot;">​</a></h3><p>Consumer là một thành phần thực hiện nhận <a href="./2024-04-15-message-la-gi.html"><strong>Message</strong></a> từ <a href="./2024-04-15-message-queue-la-gi.html"><strong>Message queue (Hàng đợi tin nhấn)</strong></a> và xử lý yêu cầu đó theo logic nghiệp vụ.</p><h2 id="mo-ta-đon-gian-cac-thuc-hoat-đong-cua-message-queue" tabindex="-1">Mô tả đơn giản các thức hoạt động của Message Queue. <a class="header-anchor" href="#mo-ta-đon-gian-cac-thuc-hoat-đong-cua-message-queue" aria-label="Permalink to &quot;Mô tả đơn giản các thức hoạt động của Message Queue.&quot;">​</a></h2><ol><li>Producer tạo ra Message cần truyền đi. Message này sẽ được truyền vào Message Queue thông qua Channel và được lưu trữ tạm thời tại đây.</li><li>Consumer lấy(Chủ động lấy) hoặc nhận Message(Queue chủ động gửi đến) từ Message Queue. Thông tin thường được lấy theo cơ chế FIFO(First in - First out), tuy nhiên vẫn có thể can thiệp vào cơ chế này thông qua định ra mức độ ưu tiên của Message. <ul><li>Tùy cách triển khai của Message Queue mà Consumer sẽ chủ động lấy dữ liệu hoặc bị động hoặc có thể hỗ trợ cả 2.</li></ul></li><li>Sau khi Consumer nhận được Message sẽ xử lý Message và thực hiện các hành động tùy vào logic nghiệp vụ của hệ thống.</li></ol><h2 id="uu-điem-cua-message-queue" tabindex="-1">Ưu điểm của Message Queue <a class="header-anchor" href="#uu-điem-cua-message-queue" aria-label="Permalink to &quot;Ưu điểm của Message Queue&quot;">​</a></h2><ol><li><strong>Bất đồng bộ</strong>:</li></ol><h2 id="ref" tabindex="-1">REF: <a class="header-anchor" href="#ref" aria-label="Permalink to &quot;REF:&quot;">​</a></h2><ul><li><a href="https://hookdeck.com/blog/introduction-message-queue" target="_blank" rel="noreferrer">https://hookdeck.com/blog/introduction-message-queue</a></li><li><a href="https://hookdeck.com/blog/message-queues-deep-dive" target="_blank" rel="noreferrer">https://hookdeck.com/blog/message-queues-deep-dive</a></li></ul>',27)];const h=e(r,[["render",function(e,n,t,u,r,h){return a(),s("div",null,g)}]]);export{u as __pageData,h as default};
